CustomField.formula:
AND(
  BEGINS(TEXT(Status), 'Resolved'),
  OR(
    /* Trường hợp 1: Normal Watcher - Không phải Owner và Không phải Creator */
    AND(
      OwnerId <> $User.Id,
      CreatedById <> $User.Id,
      OR(
        CONTAINS(FEC_Follow_Up_User__c, $User.Id),
        CONTAINS(FEC_Follow_Up_User__c, CASESAFEID($User.Id))
      )
    ),
    /* Trường hợp 2: LÀ Owner hoặc Creator -> Type = Until Unfollow (|U) */
    AND(
      OR(
        OwnerId = $User.Id,
        CreatedById = $User.Id
      ),
      OR(
        CONTAINS(FEC_Follow_Up_User__c, CASESAFEID($User.Id) & "|U"),
        CONTAINS(FEC_Follow_Up_User__c, $User.Id & "|U")
      )
    )
  )
)
